package com.hospital.management.util;import com.hospital.management.model.BillItem;import org.junit.jupiter.api.*;import java.math.*;import java.util.*;import static org.junit.jupiter.api.Assertions.*;class BillingCalculatorTest{BillingCalculator c=new BillingCalculator();@Test void calculatesLineSubtotalTaxDiscountAndBalance(){BillItem i=new BillItem();i.setLineTotal(c.calculateLineTotal(new BigDecimal("2.50"),new BigDecimal("10.555")));assertEquals(new BigDecimal("26.40"),i.getLineTotal());BigDecimal sub=c.calculateSubtotal(List.of(i));assertEquals(new BigDecimal("26.40"),sub);BigDecimal total=c.calculateTotal(sub,new BigDecimal("2.60"),new BigDecimal("1.00"));assertEquals(new BigDecimal("28.00"),total);assertEquals(new BigDecimal("8.00"),c.calculateBalance(total,new BigDecimal("20")));}@Test void rejectsNegativeAndOverpayment(){assertThrows(IllegalArgumentException.class,()->c.calculateTotal(BigDecimal.ONE,new BigDecimal("-1"),BigDecimal.ZERO));assertThrows(IllegalArgumentException.class,()->c.calculateBalance(BigDecimal.ONE,new BigDecimal("2")));}@Test void derivesFinancialStatuses(){assertEquals("UNPAID",c.deriveBillStatus(BigDecimal.TEN,BigDecimal.ZERO,"UNPAID"));assertEquals("PARTIALLY_PAID",c.deriveBillStatus(BigDecimal.TEN,BigDecimal.ONE,"UNPAID"));assertEquals("PAID",c.deriveBillStatus(BigDecimal.TEN,BigDecimal.TEN,"UNPAID"));assertEquals("CANCELLED",c.deriveBillStatus(BigDecimal.TEN,BigDecimal.ZERO,"CANCELLED"));}}
